VALUES
  ('cpa-moex-00701', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非公開發行股票之A公司董事會決議，將於6月30日召開股東常會。下列敘述何者錯誤？ A公司最晚應於6月9日寄發開會通知給股東', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00702', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '非公開發行之非閉鎖性A公司，設置董事5人，監察人2人，A公司除已發行普通股500萬股 外，並已發行每股10個表決權之複數表決權特別股50萬股，而股東甲持有3萬股普通股、1萬 股特別股。下列關於監察人之敘述，何者正確？ A公司監察人選舉時，甲有8萬個選舉權 A公司之監察人選舉，不得採候選人提名制度 A公司監察人之一人解任時，董事會應於三十日內召開股東臨時會補選', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00703', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列關於無票面金額股之敘述，何者正確？ 應全數撥充資本 每股金額，自轉換基準日起，視為無記載。公司無須通知各股東換取股票 票面金額股全數轉換為票面金額股', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00704', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列關於董事候選人提名制度之敘述，何者正確？ 於章程載明採董事候選人提名制度 被提名 人列入候選人名單', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00705', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列關於召集董事會之敘述，何者正確？', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00706', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司近年來跨足太陽能產業，導致公司連年虧損，於民國107年6月20日股東常會 甫決議通過虧損撥補議案。同年7月時，大陸突然宣布給予其太陽能產業價格補貼，致我國太陽 能產業全面遭受巨額損失。因業務需要，於同年 8 月會計師查核簽證財務報告時，發現 A 公司 實際虧損竟已達實收資本額二分之一，則依公司法，A公司應如何處理？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00707', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法之規定，股份有限公司之董事發現公司有受重大損害之虞時，應立即向何者報告？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00708', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法之規定，下列何者非股東會之召集權人？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00709', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司近期擬召開股東常會討論盈餘轉增資等議案，該公司並於股東常會召開前之停止 股票過戶日前，公告受理股東之提案、書面或電子受理方式、受理處所及受理期間。依公司法之 規定，下列敘述何者錯誤？ A公司股東會討論盈餘轉增資之議案，應在召集事由中列舉並說明其主要內容，不得以臨時動 議提出 A公司受理股東提案之受理期間不得少於十五日 A公司股東若不克出席股東會，得出具一委託書，並委託一人代理出席股東會', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00710', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司因財務困難且有停業之虞，但有重建更生之可能。依公司法之規定，下列何者不得向 法院聲請重整？ A公司已發行股份總數百分之十以上股份之股東 A公司三分之二以上之受僱員工 A公司總負債百分之十以上債權之債權人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00711', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司董事長甲於民國106年1月4日賣出A公司股票5,000股，每股50元，1月25日賣 出8,000股，每股68元，2月21日賣出5,000股，每股45元，之後於同年4月11日買進3,000 股，每股48元，5月10日買進8,000股，每股57元，6月1日買進6,000股，每股65元。在甲 買賣期間，其交易之A公司股票未有分配股息情事。試問A公司對甲之買賣可否及行使多少金 額之歸入權？ 60,000 元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅 94,000 元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅 115,000元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00712', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何種證券市場操縱行為，學理上稱為沖洗買賣？ 報買賣而相對成交 連續以高價買入或以低價賣出 售，或購買有價證券時，使約定人同時為購買或出售之相對行為 達倒貨出脫目的', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00713', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '證券交易法對於公開說明書之規範，下列敘述，何者正確？ 發行人負連帶賠償責任 負賠償責任', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00714', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法對於公開發行公司財務報告之相關規範，下列何者正確？①公開發行公司須於每 會計年度終了後六個月內，公告並申報會計師查核簽證、董事會通過及監察人承認之年度財務報', '["公開發行公司須於每會計年度第一季、第二季及第三季終了後三十日內，公告並申報經會 計師核閱及提報董事會之財務報告", "上市公司依法須公告、申報之財務報告事項，尚須將抄本 送證券交易所", "公開發行公司在重整期間，仍須依法揭露財務報告", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00715', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法對於財務資訊不實之民事責任規範，下列何者正確？①資訊不實之民事責任主體', '["資訊不實之民事責任主體中，發行人之職員，曾在財務 報告上簽名或蓋章者，負推定過失責任", "資訊不實之民事責任主體中，辦理財務報告簽證之會 計師，負過失責任", "資訊不實之民事責任，其損害賠償請求權，自募集、發行或買賣之日起逾 二年間不行使而消滅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00716', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲得知A上櫃公司獲利極佳，故進而取得A上櫃公司9%的股份，甲聽說我國證券交易法有「大 量取得股權之申報」制度。下列敘述，何者錯誤？ 10%之股份 586號解釋，證券交易法第43條之1第1項的「共同取得」，應以意思聯 絡為必要', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00717', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司計劃於本年度召開的股東會中進行全部董監改選。該公司為強化董事專業能力，A公 司之董事長甲商請多位已經在同業其他公司擔任董事之知名人士同意出任 A 公司董事。為能排 除競業禁止的疑慮，A公司股東會開會通知的討論事項中，除「董監改選案」，亦列上「解除董 事競業禁止限制案」，該議案之內容為：「為公司利益，擬解除本公司全體董事競業禁止之限制。」 此一作法適法性，下列敘述，何者正確？ A公司為求慎重，在股東會召集事由中加以列舉，當屬適法 A公司之作法已符合法律要求，當屬適法 體董事概括進行', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00718', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公開發行公司（下稱 A 公司），設有董事 9 席，公司為精簡人事，並達到議事效率之目的， 變更章程將公司董事席次減為3席。同時，A公司的大股東B股份有限公司於董事選舉議案中， 推派其代表人甲當選為董事；又於監察人之選舉議案中，推派其代表人乙當選為監察人。則 A 公司變更章程是否有效？又甲、乙分別當選為董事與監察人是否合法？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00719', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公司主要業務係為上市公司代銷其發行之有價證券，由此可推知 A 公司屬於下列何者證券商 類型？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00720', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 上市公司依董事會之決議，因維護信用及股東權益之必要將於集中交易市場買回 A 公司股份 50萬股，並辦理銷除股份。下列敘述，何者正確？ A公司買回股份，應於買回之日起一年內辦理變更登記 A公司董事會之決議及執行情形，除非有因故未買回股份之情形外，否則應於A公司最近一次 之股東會報告 A公司買回股份，須經董事會三分之二以上董事之出席及出席董事超過二分之一同意，方為適法 A公司買回的股份之數量比例，不得超過A公司已發行股份總數3%', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00721', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業會計法要求，凡商業任免主辦會計人員，均須經董事會通過，而在證券交易法，則只見要求 公開發行公司會計主管須具備一定之資格條件，並於任職期間內持續進修，而未見須經董事會通 過之規定，顯示： 其任免則不須經董事會通過', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00722', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計法規定，下列何種行為將處五年以下有期徒刑？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00723', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業依法備置於本機構之決算報表，商業之利害關係人是否可以查閱？ 否提供查閱，申請主管機關裁定之', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00724', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'essay', '下列為涉及薪資及人事循環之二種舞弊事件：
